export default {
    "$schema": "http://json-schema.org/draft-07/schema#",
    "$comment": "DO NOT EDIT THIS FILE.  It is generated automatically from typescript interfaces in the project.  To update, run `deno task schema` (with optional `--watch`).  In VSCode, this is run automatically for you on folder open.",
    "definitions": {
        "TrendingSymbol": {
            "type": "object",
            "properties": {
                "symbol": {
                    "type": "string"
                }
            },
            "required": [
                "symbol"
            ],
            "additionalProperties": {}
        },
        "TrendingSymbolsResult": {
            "type": "object",
            "properties": {
                "count": {
                    "type": "number"
                },
                "quotes": {
                    "type": "array",
                    "items": {
                        "$ref": "#/definitions/TrendingSymbol"
                    }
                },
                "jobTimestamp": {
                    "type": "number"
                },
                "startInterval": {
                    "type": "number"
                }
            },
            "required": [
                "count",
                "quotes",
                "jobTimestamp",
                "startInterval"
            ],
            "additionalProperties": {}
        },
        "TrendingSymbolsOptions": {
            "type": "object",
            "properties": {
                "lang": {
                    "type": "string"
                },
                "region": {
                    "type": "string"
                },
                "count": {
                    "type": "number"
                }
            },
            "additionalProperties": false
        },
        "trendingSymbols": {}
    }
};
